from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from sqlalchemy.orm import Session
from .database import engine, get_db
from .models import Book

app = FastAPI()

class BookCreate(BaseModel):
    title: str
    author: str
    isbn: str
    publisher: str
    year_published: int

class BookUpdate(BaseModel):
    title: str = None
    author: str = None
    isbn: str = None
    publisher: str = None
    year_published: int = None

def get_book(db: Session, book_id: int):
    return db.query(Book).filter(Book.id == book_id).first()

def create_book(db: Session, book: BookCreate):
    db_book = Book(**book.dict())
    db.add(db_book)
    db.commit()
    db.refresh(db_book)
    return db_book

def update_book(db: Session, book_id: int, book_update: BookUpdate):
    db_book = get_book(db, book_id)
    if not db_book:
        raise HTTPException(status_code=404, detail="Book not found")
    for key, value in book_update.dict(exclude_unset=True).items():
        setattr(db_book, key, value)
    db.commit()
    db.refresh(db_book)
    return db_book

def delete_book(db: Session, book_id: int):
    db_book = get_book(db, book_id)
    if not db_book:
        raise HTTPException(status_code=404, detail="Book not found")
    db.delete(db_book)
    db.commit()

@app.post('/books/', response_model=BookCreate)
def create_new_book(book: BookCreate, db: Session = Depends(get_db)):
    return create_book(db, book)

@app.get('/books/{book_id}', response_model=BookCreate)
def read_book(book_id: int, db: Session = Depends(get_db)):
    db_book = get_book(db, book_id)
    if not db_book:
        raise HTTPException(status_code=404, detail="Book not found")
    return db_book

@app.put('/books/{book_id}', response_model=BookCreate)
def update_existing_book(book_id: int, book_update: BookUpdate, db: Session = Depends(get_db)):
    return update_book(db, book_id, book_update)

@app.delete('/books/{book_id}')
def delete_existing_book(book_id: int, db: Session = Depends(get_db)):
    delete_book(db, book_id)
    return {'message': 'Book deleted'}

