from fastapi import FastAPI, Depends, HTTPException
from pydantic import BaseModel
import psycopg2
from typing import List

app = FastAPI()

class Customer(BaseModel):
    id: int
    name: str
    email: str

def get_db_connection():
    conn = psycopg2.connect(
        dbname='crm',
        user='user',
        password='password',
        host='localhost'
    )
    return conn

def get_customer(db, customer_id):
    cur = db.cursor()
    cur.execute('SELECT * FROM customers WHERE id = %s', (customer_id,))
    row = cur.fetchone()
    if not row:
        raise HTTPException(status_code=404, detail='Customer not found')
    return Customer(id=row[0], name=row[1], email=row[2])

@app.post('/customers/', response_model=Customer)
def create_customer(customer: Customer, db: psycopg2.extensions.connection = Depends(get_db_connection)):
    cur = db.cursor()
    cur.execute('INSERT INTO customers (name, email) VALUES (%s, %s) RETURNING id', (customer.name, customer.email))
    new_id = cur.fetchone()[0]
    db.commit()
    return Customer(id=new_id, name=customer.name, email=customer.email)

@app.get('/customers/{customer_id}', response_model=Customer)
def read_customer(customer_id: int, db: psycopg2.extensions.connection = Depends(get_db_connection)):
    return get_customer(db, customer_id)

@app.put('/customers/{customer_id}', response_model=Customer)
def update_customer(customer_id: int, customer: Customer, db: psycopg2.extensions.connection = Depends(get_db_connection)):
    cur = db.cursor()
    cur.execute('UPDATE customers SET name = %s, email = %s WHERE id = %s', (customer.name, customer.email, customer_id))
    if cur.rowcount == 0:
        raise HTTPException(status_code=404, detail='Customer not found')
    db.commit()
    return Customer(id=customer_id, name=customer.name, email=customer.email)

@app.delete('/customers/{customer_id}')
def delete_customer(customer_id: int, db: psycopg2.extensions.connection = Depends(get_db_connection)):
    cur = db.cursor()
    cur.execute('DELETE FROM customers WHERE id = %s', (customer_id,))
    if cur.rowcount == 0:
        raise HTTPException(status_code=404, detail='Customer not found')
    db.commit()
    return {'message': 'Customer deleted'}

