    plan = db.query(models.Plan).filter(models.Plan.id == plan_id).first()
    if not plan:
        raise HTTPException(status_code=404, detail='Plan not found')
    subscription = models.Subscription(user_id=user_id, plan_id=plan_id, start_date=datetime.utcnow(), end_date=datetime.utcnow() + timedelta(days=30))
    db.add(subscription)
