from fastapi import FastAPI, HTTPException, Depends
from sqlalchemy.orm import Session
import crud
import schemas
from database import get_db

app = FastAPI()

def validate_stock_transfer(db: Session, product_id: int, source_warehouse_id: int, target_warehouse_id: int, quantity: int):
    product = crud.get_product(db, product_id)
    if not product:
        raise HTTPException(status_code=404, detail="Product not found")
    source_warehouse = crud.get_warehouse(db, source_warehouse_id)
    target_warehouse = crud.get_warehouse(db, target_warehouse_id)
    if not source_warehouse or not target_warehouse:
        raise HTTPException(status_code=404, detail="Warehouse not found")
    if quantity <= 0:
        raise HTTPException(status_code=422, detail="Quantity must be positive")
    stock = crud.get_stock(db, product_id, source_warehouse_id)
    if not stock or stock.quantity < quantity:
        raise HTTPException(status_code=400, detail="Insufficient stock in the source warehouse")

@app.post('/stock-transfers/', response_model=schemas.StockTransfer)
def create_stock_transfer(stock_transfer: schemas.StockTransferCreate, db: Session = Depends(get_db)):
    validate_stock_transfer(db, stock_transfer.product_id, stock_transfer.source_warehouse_id, stock_transfer.target_warehouse_id, stock_transfer.quantity)
    return crud.create_stock_transfer(db=db, stock_transfer=stock_transfer)

