from fastapi import APIRouter, Depends, HTTPException, status
from sqlalchemy.orm import Session
from typing import List
import models, schemas
crud_volunteers = crud_volunteers.CrudVolunteers()
router = APIRouter()

def get_db():
    db = database.SessionLocal()
    try:
        yield db
    finally:
        db.close()

@router.post('/volunteers/signup', response_model=schemas.VolunteerRead)
def signup_volunteer(volunteer: schemas.VolunteerCreate, db: Session = Depends(get_db)):
    existing_user = crud_volunteers.get_by_email(db=db, email=volunteer.email)
