from fastapi import FastAPI, HTTPException, Depends
from sqlalchemy.orm import Session
from . import crud_opportunities, crud_volunteers, schemas, models
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

app = FastAPI()

@app.post("/opportunities/", response_model=schemas.OpportunityRead)
def create_opportunity(opportunity: schemas.OpportunityCreate, db: Session = Depends(get_db)):
    if crud_opportunities.get_opportunity_by_title(db, title=opportunity.title):
        raise HTTPException(status_code=400, detail="Opportunity already exists")
    return crud_opportunities.create_opportunity(db=db, opportunity=opportunity)

@app.get("/opportunities/{opportunity_id}", response_model=schemas.OpportunityRead)
def read_opportunity(opportunity_id: int, db: Session = Depends(get_db)):
    db_opportunity = crud_opportunities.get_opportunity(db, opportunity_id=opportunity_id)
    if db_opportunity is None:
        raise HTTPException(status_code=404, detail="Opportunity not found")
    return db_opportunity

@app.put("/opportunities/{opportunity_id}", response_model=schemas.OpportunityRead)
def update_opportunity(opportunity_id: int, opportunity: schemas.OpportunityCreate, db: Session = Depends(get_db)):
    db_opportunity = crud_opportunities.get_opportunity(db, opportunity_id=opportunity_id)
    if db_opportunity is None:
        raise HTTPException(status_code=404, detail="Opportunity not found")
    return crud_opportunities.update_opportunity(db=db, opportunity_id=opportunity_id, opportunity=opportunity)

@app.delete("/opportunities/{opportunity_id}")
def delete_opportunity(opportunity_id: int, db: Session = Depends(get_db)):
    db_opportunity = crud_opportunities.get_opportunity(db, opportunity_id=opportunity_id)
    if db_opportunity is None:
        raise HTTPException(status_code=404, detail="Opportunity not found")
    return crud_opportunities.delete_opportunity(db=db, opportunity_id=opportunity_id)

@app.post("/volunteers/signup", response_model=schemas.VolunteerRead)
def signup_volunteer(volunteer: schemas.VolunteerCreate, db: Session = Depends(get_db)):
    if crud_volunteers.get_volunteer_by_email(db, email=volunteer.email):
        raise HTTPException(status_code=400, detail="Email already registered")
    return crud_volunteers.create_volunteer(db=db, volunteer=volunteer)
